import re
from collections.abc import Callable
from pathlib import Path

from src.models import Brand, GuardrailCheck

RuleMatcher = Callable[[list[str]], bool]

_FALLBACK_SEVERITY: dict[str, str] = {
    "R1": "WARN",
    "R2": "BLOCK",
    "R3": "WARN",
    "R4": "BLOCK",
    "R5": "BLOCK",
}


def run_checks(diff: str, brand: Brand) -> list[GuardrailCheck]:
    added = _added_lines(diff)
    sev = _parse_severities(brand)
    return [
        _check("R1", sev.get("R1", "WARN"), _has_relative_import, added),
        _check("R2", sev.get("R2", "BLOCK"), _has_shell_execution, added),
        _check(
            "R3", sev.get("R3", "WARN"), _has_public_function_without_docstring, added
        ),
        _check("R4", sev.get("R4", "BLOCK"), _has_print_call, added),
        _check("R5", sev.get("R5", "BLOCK"), _has_requests_call, added),
    ]


def _parse_severities(brand: Brand) -> dict[str, str]:
    try:
        text = Path(f"{brand}/AGENTS.md").read_text()
    except FileNotFoundError:
        return _FALLBACK_SEVERITY.copy()
    pattern = re.compile(r"-\s+(R\d+)\s+(WARN|BLOCK|INFO):")
    parsed = {m.group(1): m.group(2) for m in pattern.finditer(text)}
    return {**_FALLBACK_SEVERITY, **parsed}


def _added_lines(diff: str) -> list[str]:
    return [
        line[1:]
        for line in diff.splitlines()
        if line.startswith("+") and not line.startswith("+++")
    ]


def _check(
    rule_id: str,
    severity: str,
    matcher: RuleMatcher,
    added: list[str],
) -> GuardrailCheck:
    result = "fail" if matcher(added) else "pass"
    return GuardrailCheck(
        ruleId=rule_id,
        severity=severity,
        result=result,
        reason=f"per AGENTS.md {rule_id}",
    )


def _has_relative_import(added: list[str]) -> bool:
    return any(re.search(r"^\s*from\s+\.", line) for line in added)


def _has_shell_execution(added: list[str]) -> bool:
    pattern = re.compile(r"\b(os\.system|subprocess(?:\.|\b))")
    return any(pattern.search(line) for line in added)


def _has_public_function_without_docstring(added: list[str]) -> bool:
    for index, line in enumerate(added):
        has_missing_docstring = not _next_added_line_is_docstring(added, index)
        if _is_public_function(line) and has_missing_docstring:
            return True
    return False


def _is_public_function(line: str) -> bool:
    return re.search(r"^\s*def\s+(?!_)[A-Za-z_]\w*\s*\(", line) is not None


def _next_added_line_is_docstring(added: list[str], index: int) -> bool:
    for line in added[index + 1 :]:
        stripped = line.strip()
        if not stripped:
            continue
        return stripped.startswith(('"""', "'''"))
    return False


def _has_print_call(added: list[str]) -> bool:
    return any(re.search(r"(^|[^\w.])print\s*\(", line) for line in added)


def _has_requests_call(added: list[str]) -> bool:
    pattern = re.compile(r"\brequests\.(get|post|put|patch|delete|head|options)\s*\(")
    return any(pattern.search(line) for line in added)

from src.guardrails import run_checks


def test_empty_patch_passes_all_rules() -> None:
    checks = run_checks("", "efood")

    assert len(checks) == 5
    assert {check.ruleId for check in checks} == {"R1", "R2", "R3", "R4", "R5"}
    assert all(check.result == "pass" for check in checks)


def test_r1_warns_on_relative_import() -> None:
    checks = run_checks("+from .models import Session", "efood")

    assert _result(checks, "R1") == "fail"
    assert _severity(checks, "R1") == "WARN"


def test_r2_blocks_os_system() -> None:
    checks = run_checks("+os.system(command)", "efood")

    assert _result(checks, "R2") == "fail"
    assert _severity(checks, "R2") == "BLOCK"


def test_r2_blocks_subprocess_import_or_usage() -> None:
    checks = run_checks("+import subprocess\n+subprocess.run(command)", "efood")

    assert _result(checks, "R2") == "fail"
    assert _severity(checks, "R2") == "BLOCK"


def test_r3_warns_on_public_function_without_docstring() -> None:
    checks = run_checks("+def create_item():\n+    return None", "efood")

    assert _result(checks, "R3") == "fail"
    assert _severity(checks, "R3") == "WARN"


def test_r3_passes_public_function_with_docstring() -> None:
    diff = '+def create_item():\n+    """Create an item."""\n+    return None'
    checks = run_checks(diff, "efood")

    assert _result(checks, "R3") == "pass"


def test_r4_blocks_print_call() -> None:
    checks = run_checks("+print(value)", "efood")

    assert _result(checks, "R4") == "fail"
    assert _severity(checks, "R4") == "BLOCK"


def test_r5_blocks_requests_call() -> None:
    checks = run_checks("+requests.post(url, json=payload)", "efood")

    assert _result(checks, "R5") == "fail"
    assert _severity(checks, "R5") == "BLOCK"


def test_only_added_lines_are_checked() -> None:
    diff = "--- a/app.py\n+++ b/app.py\n-print(secret)\n context\n+value = 1"

    checks = run_checks(diff, "efood")

    assert all(check.result == "pass" for check in checks)


def _result(checks: list[object], rule_id: str) -> str:
    return next(check.result for check in checks if check.ruleId == rule_id)


def _severity(checks: list[object], rule_id: str) -> str:
    return next(check.severity for check in checks if check.ruleId == rule_id)

